class Solution:
    def maxChunksToSorted(self, arr):
        target = sorted(arr)
        chunks = 0
        i = 0
        n = len(arr)
        while i < n:
            j = i
            while True:
                left = sorted(arr[i:j + 1])
                if left == target[i:j + 1]:
                    break
                j += 1
            chunks += 1
            i = j + 1
        return chunks

